    def resolve_dynamic_default(self, ctx: Context) -> t.Any | None:
        """Resolve this option's dynamic default, if any, based on the
        current values of the options it depends on.

        Later entries in the dynamic default mapping take precedence
        over earlier ones. Returns ``None`` if there is no dynamic
        default or none of its mappings match.

        .. versionadded:: 8.3
        """
        if self._dynamic_default is None:
            return None

        value = None

        for source_decl, mapping in self._dynamic_default.items():
            source_param = next(
                (
                    param
                    for param in ctx.command.get_params(ctx)
                    if source_decl in param.opts or source_decl in param.secondary_opts
                ),
                None,
            )

            if source_param is None:
                continue

            source_value = ctx.params.get(source_param.name)
            key = str(source_value)

            if key in mapping:
                value = mapping[key]

